# [4] FAKE FLOW & DECODE (Giấu nhẹm chữ base64 và zlib, gọi bằng API ngầm)
_b85 = __import__('base64').b85decode
_zdc = __import__('zlib').decompress
_mld = __import__('marshal').loads

def _vm_run():
    # Giải mã nhị phân
    _raw = _b85(_p)
    _dec = bytearray((b ^ _k) for b in _raw)
    _core = _mld(_zdc(_dec))
    
    # [5] KÍCH NỔ BẰNG FUNCTION TYPE (TUYỆT ĐỐI KHÔNG DÙNG EXEC)
    # Bơm thẳng mã Bytecode vào lõi của Python, hook exec() vô dụng!
    _engine = types.FunctionType(_core, globals())
    _engine()

# Khởi động
if __name__ == '__main__':
    _vm_run()
